Sure! Below is an example code for a Discord bot using Discord.js v14 that includes a single slash command called `ban`. This bot will ban a user from the server when the command is executed.

1. **Ensure you have the necessary npm packages installed**:
   ```sh
   npm install discord.js
   ```

2. **Create a new JavaScript file** (e.g., `bot.js`):
   ```javascript
   const { Client, GatewayIntentBits, PermissionsBitField } = require('discord.js');

   const client = new Client({
       intents: [
           GatewayIntentBits.Guilds,
           GatewayIntentBits.GuildMembers,
           GatewayIntentBits.GuildMessages,
           GatewayIntentBits.MessageContent,
       ],
   });

   client.once('ready', () => {
       console.log(`Logged in as ${client.user.tag}!`);
   });

   client.on('interactionCreate', async interaction => {
       if (!interaction.isChatInputCommand()) return;

       const { commandName } = interaction;

       if (commandName === 'ban') {
           if (!interaction.member.permissions.has(PermissionsBitField.Flags.BanMembers)) {
               return interaction.reply({ content: 'You do not have permission to use this command.', ephemeral: true });
           }

           const user = interaction.options.getUser('user');
           const member = await interaction.guild.members.fetch(user.id);

           if (!member) {
               return interaction.reply({ content: 'User not found in the server.', ephemeral: true });
           }

           try {
               await member.ban();
               return interaction.reply({ content: `${user.tag} has been banned.`, ephemeral: true });
           } catch (err) {
               console.error(err);
               return interaction.reply({ content: 'There was an error while trying to ban the user.', ephemeral: true });
           }
       }
   });

   client.on('error', console.error);
   client.on('warn', console.warn);

   client.login('YOUR_BOT_TOKEN');
   ```

3. **Create an application on the Discord Developer Portal**:
   - Go to [Discord Developer Portal](https://discord.com/developers/applications) and create a new application.
   - Under the "OAuth2" section, create a new OAuth2 URL to authorize your bot with the `ban_members` permission.

4. **Add the slash command to your bot**:
   - Under the "Bot" section, click on "OAuth2" and then "URL Generator".
   - Select the `bot` and `applications.commands` scopes.
   - Select the `ban_members` permission.
   - Copy the generated URL and paste it into your browser to authorize your bot with the required permissions.

5. **Run your bot**:
   ```sh
   node bot.js
   ```

Replace `'YOUR_BOT_TOKEN'` with your actual Discord bot token.

With this setup, your bot will be able to receive and process the `ban` command with slash command syntax, banning the specified user from the server if the bot and user have the necessary permissions.

Sure! Below is a simple C++ function that takes a reference to a `std::string` containing markdown formatted text and returns a `std::string` containing HTML formatted text. This example uses basic markdown syntax conversion to HTML. For a more comprehensive and accurate conversion, consider using a library like `markdowncpp`.

```cpp
#include <iostream>
#include <string>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
    std::string html = markdown;

    // Convert markdown headers
    html = std::regex_replace(html, std::regex(R"(^# (.+)$)"), "<h1>$1</h1>");
    html = std::regex_replace(html, std::regex(R"(^## (.+)$)"), "<h2>$1</h2>");
    html = std::regex_replace(html, std::regex(R"(^### (.+)$)"), "<h3>$1</h3>");
    html = std::regex_replace(html, std::regex(R"(^#### (.+)$)"), "<h4>$1</h4>");
    html = std::regex_replace(html, std::regex(R"(^##### (.+)$)"), "<h5>$1</h5>");
    html = std::regex_replace(html, std::regex(R"(^###### (.+)$)"), "<h6>$1</h6>");

    // Convert bold and italic
    html = std::regex_replace(html, std::regex(R"(\*\*(.+?)\*\*)"), "<strong>$1</strong>");
    html = std::regex_replace(html, std::regex(R"(\*(.+?)\*)"), "<em>$1</em>");

    // Convert links
    html = std::regex_replace(html, std::regex(R"(\[(.+?)\]\((.+?)\))"), "<a href=\"$2\">$1</a>");

    // Convert inline code
    html = std::regex_replace(html, std::regex(R"(\`(.+?)\`)"), "<code>$1</code>");

    return html;
}

int main() {
    std::string markdown = "# Hello, World!\nThis is a paragraph with **bold** and *italic* text.\n[Link to Google](https://www.google.com).\n```\nThis is a code block.\n```";
    std::string html = markdownToHtml(markdown);

    std::cout << "Markdown:\n" << markdown << "\n\nHTML:\n" << html << std::endl;

    return 0;
}
```

### Explanation:
1. **Headers**: The function uses `std::regex_replace` to replace markdown headers with corresponding HTML tags.
2. **Bold and Italic**: It converts markdown bold (`**text**`) and italic (`*text*`) to HTML `<strong>` and `<em>` tags, respectively.
3. **Links**: Markdown links (`[text](url)`) are replaced with HTML `<a>` tags.
4. **Inline Code**: Inline code (```text```) is replaced with HTML `<code>` tags.

This example covers basic markdown syntax. For more complex transformations, consider using a more comprehensive markdown-to-HTML converter library.

