Sure! Below is an example of HTML code that imitates a fake chatbot using a modal. The modal displays a chat history with 4 overall messages, including 2 messages from the bot and 2 messages from the human.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Chatbot Modal</title>
  <style>
    /* Basic styling for the modal */
   .modal {
      display: none;
      position: fixed;
      z-index: 1;
      left: 0;
      top: 0;
      width: 100%;
      height: 100%;
      overflow: auto;
      background-color: rgb(0,0,0);
      background-color: rgba(0,0,0,0.4);
      padding-top: 60px;
    }

   .modal-content {
      background-color: #fefefe;
      margin: 5% auto;
      padding: 20px;
      border: 1px solid #888;
      width: 80%;
    }

   .close {
      color: #aaa;
      float: right;
      font-size: 28px;
      font-weight: bold;
    }

   .close:hover,
   .close:focus {
      color: black;
      text-decoration: none;
      cursor: pointer;
    }

    /* Clearfix for chat messages */
   .chat-history::after {
      content: "";
      display: table;
      clear: both;
    }

   .message {
      float: left;
      padding: 10px;
      margin: 5px;
      background-color: #f1f1f1;
      border: 1px solid #ccc;
      border-radius: 5px;
      max-width: 70%;
    }

   .bot-message {
      background-color: #c0c0c0;
    }
  </style>
</head>
<body>

<!-- Button to open the modal -->
<button id="openModal">Open Chat History</button>

<!-- The Modal -->
<div id="chatModal" class="modal">
  <div class="modal-content">
    <span class="close">&times;</span>
    <div class="chat-history">
      <div class="message">Human: Hi there!</div>
      <div class="message bot-message">Bot: Hello! How can I assist you today?</div>
      <div class="message">Human: Can you help me with a problem?</div>
      <div class="message bot-message">Bot: Of course! What seems to be the issue?</div>
    </div>
  </div>
</div>

<script>
  // Get the modal
  var modal = document.getElementById("chatModal");

  // Get the button that opens the modal
  var btn = document.getElementById("openModal");

  // Get the <span> element that closes the modal
  var span = document.getElementsByClassName("close")[0];

  // When the user clicks the button, open the modal
  btn.onclick = function() {
    modal.style.display = "block";
  }

  // When the user clicks on <span> (x), close the modal
  span.onclick = function() {
    modal.style.display = "none";
  }

  // When the user clicks anywhere outside of the modal, close it
  window.onclick = function(event) {
    if (event.target == modal) {
      modal.style.display = "none";
    }
  }
</script>

</body>
</html>
```

